#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-20

# =============================================================================
# Effective-recall arithmetic regression test  (#3032 follow-up)
# =============================================================================
# Pure arithmetic, ZERO model calls. Guards the fail-open that let a skill with
# a 33% trigger rate report "PASS" off a 100% effective recall.
#
# The old denominator was `tp_partial + fn`, which placed the flaky mass in both
# the numerator and the denominator: whenever nothing hard-missed (fn == 0) it
# reduced to tp_partial/tp_partial = 100%. The denominator must instead be the
# full measured positive population (pos_total).
#
# Usage: bash tests/evals/test-effective-recall.sh
# =============================================================================

set -euo pipefail
trap 'echo "[$0] failed at line $LINENO" >&2' ERR

# NOTE: counters use `x=$((x + 1))`, never `((x++))`. Post-increment returns the
# OLD value, so the first increment from 0 exits non-zero and `set -e` would
# kill the run mid-suite.

GREEN='\033[0;32m'; RED='\033[0;31m'; BLUE='\033[0;34m'; NC='\033[0m'
pass=0; fail=0

# Mirrors the shipped formula in run-trigger-eval.sh.
eff_recall() {
    local tp_partial="$1" pos_total="$2"
    if [[ "$pos_total" -gt 0 ]]; then
        echo "scale=1; $tp_partial * 100 / $pos_total" | bc
    else
        echo "0"
    fi
}

# The old, broken formula. Kept so this test proves the bug is GONE rather than
# merely asserting that the new numbers are what they are.
eff_recall_old() {
    local tp_partial="$1" fn="$2"
    local d; d=$(echo "$tp_partial + $fn" | bc)
    if [[ $(echo "$d > 0" | bc) -eq 1 ]]; then
        echo "scale=1; $tp_partial * 100 / $d" | bc
    else
        echo "0"
    fi
}

gate() { # eff_recall -> PASS/FAIL at threshold 80
    local r="${1%.*}"; [[ -z "$r" ]] && r=0
    if [[ "$r" -lt 80 ]]; then echo FAIL; else echo PASS; fi
}

check() {
    local name="$1" got="$2" want="$3"
    if [[ "$got" == "$want" ]]; then
        echo -e "  ${GREEN}PASS${NC} $name (${got})"
        pass=$((pass + 1))
    else
        echo -e "  ${RED}FAIL${NC} $name: got ${got}, want ${want}"
        fail=$((fail + 1))
    fi
    return 0
}

echo -e "${BLUE}Effective recall: real observed runs${NC}"

# ci-sentinel, CI run 29742402853: one prompt, triggered 1 of 3 reps.
# tp=0 fn=0 flaky=1 -> tp_partial=.33, pos_total=1
check "ci-sentinel 33% trigger rate scores 33"  "$(eff_recall .33 1)"      "33.0"
check "  and the OLD formula scored it 100"     "$(eff_recall_old .33 0)"  "100.0"

# implement, same run: 3 OK, 2 MISS, 3 FLAKY (rates .33 .66 .33)
# tp_partial = 3 + 1.32 = 4.32, pos_total = 8
check "implement scores 54 on the full population" "$(eff_recall 4.32 8)"     "54.0"
check "  and the OLD formula reported 68.3"        "$(eff_recall_old 4.32 2)" "68.3"

echo -e "${BLUE}Gate behaviour (threshold 80)${NC}"
check "33.0 fails the gate"    "$(gate 33.0)"  "FAIL"
check "54.0 fails the gate"    "$(gate 54.0)"  "FAIL"
check "100.0 passes"           "$(gate 100.0)" "PASS"
check "80.0 passes (boundary)" "$(gate 80.0)"  "PASS"
check "79.9 fails (boundary)"  "$(gate 79.9)"  "FAIL"

echo -e "${BLUE}Fail-open invariant${NC}"

# The core regression: nothing hard-misses, but every prompt is flaky. The old
# formula returned 100 for every one of these. The new one must not.
for n in 1 3 5; do
    tpp=$(echo "scale=2; $n * 0.33" | bc)
    new=$(eff_recall "$tpp" "$n")
    old=$(eff_recall_old "$tpp" 0)
    if [[ "$old" == "100.0" && "$(gate "$new")" == "FAIL" ]]; then
        echo -e "  ${GREEN}PASS${NC} all-flaky x${n}: old=100.0 (fail-open) new=${new} -> FAIL"
        pass=$((pass + 1))
    else
        echo -e "  ${RED}FAIL${NC} all-flaky x${n}: old=${old} new=${new}"
        fail=$((fail + 1))
    fi
done

# A perfect run must still score 100, or this fix would red-wall every green skill.
check "all prompts OK still scores 100" "$(eff_recall 5 5)" "100.0"
# No measured positives: no division, no fabricated score.
check "empty positive population is 0"  "$(eff_recall 0 0)" "0"

echo ""
echo -e "  Passed: ${GREEN}${pass}${NC}   Failed: ${RED}${fail}${NC}"
[[ "$fail" -eq 0 ]] || exit 1
exit 0
